      h1   { font-size: 1.4rem; }
      .delimiter-group { margin-left: 0; }
    }
  </style>
</head>
<body>

<h1>📋 CSV Parser</h1>

<div class="card">
  <label for="csvInput">Paste your CSV data below:</label>
  <textarea id="csvInput" spellcheck="false" placeholder='Example:
Name, Age, "City, State", Notes
"Alice ""The Great""", 30, "New York, NY", "Loves hiking"
Bob, 25, "Austin, TX", ""
Carol, , "Chicago, IL", "Enjoys ""cooking"""'></textarea>

  <div class="controls">
    <button id="parseBtn">▶ Parse CSV</button>
    <button id="clearBtn">✕ Clear</button>
    <div class="delimiter-group">
      <label for="delimSelect">Delimiter:</label>
      <select id="delimSelect">
        <option value=",">Comma ( , )</option>
        <option value=";">Semicolon ( ; )</option>
        <option value="	">Tab ( \t )</option>
        <option value="|">Pipe ( | )</option>
      </select>
    </div>
  </div>
  <div id="message" class="info"></div>
</div>

<div id="tableWrapper"></div>

<script>
  // ─── CSV Parser ────────────────────────────────────────────────────────────
  /**
   * Parses a CSV string into a 2-D array of strings.
   * Handles:
   *  - Quoted fields containing the delimiter
   *  - Escaped double-quotes ("") inside quoted fields
   *  - Fields that span multiple lines inside quotes
   *  - Varying column counts across rows
   *  - CRLF, LF, and CR line endings
   */
  function parseCSV(text, delimiter = ',') {
    const rows   = [];
    let   row    = [];
    let   field  = '';
    let   inQuote = false;
    let   i      = 0;
    const len    = text.length;

    while (i < len) {
      const ch   = text[i];
      const next = text[i + 1];

      if (inQuote) {
        if (ch === '"') {
          if (next === '"') {
            // Escaped quote → literal "
            field += '"';
            i += 2;
          } else {
            // Closing quote
            inQuote = false;
            i++;
          }
        } else {
          field += ch;
          i++;
        }
      } else {
        if (ch === '"') {
          inQuote = true;
          i++;
        } else if (ch === delimiter) {
          row.push(field);
          field = '';
          i++;
        } else if (ch === '\r' && next === '\n') {
          // CRLF
          row.push(field);
          rows.push(row);
          row   = [];
          field = '';
          i += 2;
        } else if (ch === '\r' || ch === '\n') {
          // CR or LF
          row.push(field);
          rows.push(row);
          row   = [];
          field = '';
          i++;
        } else {
          field += ch;
          i++;
        }
      }
    }

    // Push last field / row (file may not end with newline)
    row.push(field);
    // Avoid pushing a single empty row for trailing newline
    if (!(rows.length > 0 && row.length === 1 && row[0] === '')) {
      rows.push(row);
    }

    return rows;
  }

  // ─── Table Builder ─────────────────────────────────────────────────────────
  function buildTable(rows) {
    if (rows.length === 0) return null;

    // Find the maximum column count across all rows
    const maxCols = rows.reduce((m, r) => Math.max(m, r.length), 0);

    const table  = document.createElement('table');
    const thead  = document.createElement('thead');
    const tbody  = document.createElement('tbody');

    // ── Header row (first CSV row) ──
    const headerRow = document.createElement('tr');

    // Row-number header cell
    const thNum = document.createElement('th');
    thNum.textContent = '#';
    thNum.className   = 'row-num';
    headerRow.appendChild(thNum);

    const headerData = rows[0];
    for (let c = 0; c < maxCols; c++) {
      const th = document.createElement('th');
      th.textContent = (headerData[c] !== undefined && headerData[c] !== '')
        ? headerData[c]
        : `Column ${c + 1}`;
      headerRow.appendChild(th);
    }
    thead.appendChild(headerRow);
    table.appendChild(thead);

    // ── Data rows ──
    for (let r = 1; r < rows.length; r++) {
      const tr   = document.createElement('tr');
      const data = rows[r];

      // Row number cell
      const tdNum = document.createElement('td');
      tdNum.textContent = r;
      tdNum.className   = 'row-num';
      tr.appendChild(tdNum);

      for (let c = 0; c < maxCols; c++) {
        const td  = document.createElement('td');
        const val = data[c];

        if (val === undefined || val === '') {
          td.textContent = val === undefined ? '—' : '';
          td.classList.add('empty-cell');
        } else {
          td.textContent = val;
        }
        tr.appendChild(td);
      }
      tbody.appendChild(tr);
    }

    table.appendChild(tbody);
    return { table, rowCount: rows.length - 1, colCount: maxCols };
  }

  // ─── UI Logic ──────────────────────────────────────────────────────────────
  const csvInput    = document.getElementById('csvInput');
  const parseBtn    = document.getElementById('parseBtn');
  const clearBtn    = document.getElementById('clearBtn');
  const delimSelect = document.getElementById('delimSelect');
  const message     = document.getElementById('message');
  const wrapper     = document.getElementById('tableWrapper');

  function setMessage(text, type = 'info') {
    message.textContent  = text;
    message.className    = type;
  }

  function renderTable() {
    const raw = csvInput.value.trim();

    if (!raw) {
      setMessage('⚠ Please paste some CSV data first.', 'error');
      wrapper.style.display = 'none';
      wrapper.innerHTML     = '';
      return;
    }

    const delimiter = delimSelect.value;
    let rows;

    try {
      rows = parseCSV(raw, delimiter);
    } catch (e) {
      setMessage('✕ Parse error: ' + e.message, 'error');
      return;
    }

    if (rows.length === 0 || (rows.length === 1 && rows[0].every(f => f === ''))) {
      setMessage('⚠ No data found after parsing.', 'error');
      wrapper.style.display = 'none';
      wrapper.innerHTML     = '';
      return;
    }

    const result = buildTable(rows);
    if (!result) {
      setMessage('⚠ Could not build table.', 'error');
      return;
    }

    wrapper.innerHTML     = '';
    wrapper.appendChild(result.table);
    wrapper.style.display = 'block';

    const noun = result.rowCount === 1 ? 'row' : 'rows';
    setMessage(
      `✔ Parsed ${result.rowCount} data ${noun} × ${result.colCount} columns.`,
      'success'
    );

    wrapper.scrollIntoView({ behavior: 'smooth', block: 'start' });
  }

  parseBtn.addEventListener('click', renderTable);

  clearBtn.addEventListener('click', () => {
    csvInput.value        = '';
    wrapper.innerHTML     = '';
    wrapper.style.display = 'none';
    setMessage('', 'info');
    csvInput.focus();
  });

  // Allow Ctrl+Enter to parse quickly
  csvInput.addEventListener('keydown', e => {
    if (e.key === 'Enter' && (e.ctrlKey || e.metaKey)) {
      renderTable();
    }
  });
</script>
</body>
</html>
