<body>
<div class="container">

    <header>
        <h1>📊 CSV to Table Converter</h1>
        <p>Paste your CSV data below and click <strong>Parse CSV</strong> to render a formatted table.</p>
    </header>

    <!-- Input Card -->
    <div class="card">
        <label for="csvInput">CSV Input</label>
        <textarea id="csvInput" placeholder='Paste CSV data here…&#10;&#10;Example:&#10;Name,Age,City&#10;"Smith, John",30,"New York"&#10;Jane,25,London'></textarea>

        <div class="options-row">
            <div class="option-group">
                <label for="delimiterSelect">Delimiter:</label>
                <select id="delimiterSelect">
                    <option value="," selected>Comma (,)</option>
                    <option value=";">Semicolon (;)</option>
                    <option value="&#9;">Tab (\t)</option>
                    <option value="|">Pipe (|)</option>
                    <option value="custom">Custom…</option>
                </select>
                <input type="text" id="customDelimiter" placeholder="," style="display:none;" maxlength="3">
            </div>

            <div class="checkbox-group">
                <input type="checkbox" id="hasHeader" checked>
                <label for="hasHeader">First row is header</label>
            </div>

            <div class="checkbox-group">
                <input type="checkbox" id="trimWhitespace" checked>
                <label for="trimWhitespace">Trim whitespace</label>
            </div>

            <div class="checkbox-group">
                <input type="checkbox" id="showRowNums" checked>
                <label for="showRowNums">Show row numbers</label>
            </div>
        </div>

        <div class="button-row">
            <button id="parseBtn">▶ Parse CSV</button>
            <button id="sampleBtn">📋 Load Sample</button>
            <button id="clearBtn">✕ Clear</button>
        </div>

        <div id="status"></div>
    </div>

    <!-- Output Card -->
    <div class="card" id="outputCard">
        <div class="output-header">
            <div>
                <h2>Table Output</h2>
                <span class="output-meta" id="outputMeta"></span>
            </div>
            <button id="copyBtn">📋 Copy HTML</button>
        </div>
        <div class="table-wrapper">
            <table id="outputTable"></table>
        </div>
    </div>

</div>

<script>
    // ── DOM refs ──────────────────────────────────────────────
    const csvInput        = document.getElementById('csvInput');
    const delimiterSelect = document.getElementById('delimiterSelect');
    const customDelimiter = document.getElementById('customDelimiter');
    const hasHeaderCb     = document.getElementById('hasHeader');
    const trimWsCb        = document.getElementById('trimWhitespace');
    const showRowNumsCb   = document.getElementById('showRowNums');
    const parseBtn        = document.getElementById('parseBtn');
    const sampleBtn       = document.getElementById('sampleBtn');
    const clearBtn        = document.getElementById('clearBtn');
    const copyBtn         = document.getElementById('copyBtn');
    const statusEl        = document.getElementById('status');
    const outputCard      = document.getElementById('outputCard');
    const outputTable     = document.getElementById('outputTable');
    const outputMeta      = document.getElementById('outputMeta');

    // ── Sample data ───────────────────────────────────────────
    const SAMPLE_CSV = `Name,Age,City,Occupation,Notes
"Smith, John",30,"New York","Software Engineer","Loves ""clean code"" and coffee"
Jane Doe,25,London,Designer,
"O'Brien, Pat",42,"San Francisco",Manager,"Works remotely, part-time"
Carlos Mendez,35,Madrid,Analyst,N/A
"Li, Wei",28,Beijing,"Data Scientist","Specializes in ML, NLP, and CV"
Anna Müller,31,Berlin,Developer,"Uses semicolons; carefully"
,,,, 
Tom Hanks,67,"Los Angeles","Actor / Director","Multiple award winner"`;

    // ── Delimiter handling ────────────────────────────────────
    delimiterSelect.addEventListener('change', () => {
        customDelimiter.style.display =
            delimiterSelect.value === 'custom' ? 'inline-block' : 'none';
    });

    function getDelimiter() {
        if (delimiterSelect.value === 'custom') {
            return customDelimiter.value || ',';
        }
        return delimiterSelect.value;
    }

    // ── CSV Parser ────────────────────────────────────────────
    /**
     * RFC 4180-compliant CSV parser with extras:
     *  - Quoted fields (may contain delimiter and newlines)
     *  - Escaped quotes ("")
     *  - Varying column counts per row
     *  - CRLF / LF / CR line endings
     */
    function parseCSV(text, delimiter) {
        const rows = [];
        let row = [];
        let field = '';
        let inQuotes = false;
        let i = 0;
        const len = text.length;
        const delLen = delimiter.length;

        while (i < len) {
            const ch = text[i];

            if (inQuotes) {
                if (ch === '"') {
                    // Peek ahead for escaped quote ("")
                    if (i + 1 < len && text[i + 1] === '"') {
                        field += '"';
                        i += 2;
                    } else {
                        // Closing quote
                        inQuotes = false;
                        i++;
                    }
                } else {
                    field += ch;
                    i++;
                }
            } else {
                // Check for delimiter (supports multi-char delimiters)
                if (text.startsWith(delimiter, i)) {
                    row.push(field);
                    field = '';
                    i += delLen;
                } else if (ch === '"') {
                    inQuotes = true;
                    i++;
                } else if (ch === '\r') {
                    // CR or CRLF
                    row.push(field);
                    field = '';
                    rows.push(row);
                    row = [];
                    i++;
                    if (i < len && text[i] === '\n') i++; // consume LF
                } else if (ch === '\n') {
                    row.push(field);
                    field = '';
                    rows.push(row);
                    row = [];
                    i++;
                } else {
                    field += ch;
                    i++;
                }
            }
        }

        // Push last field / row
        row.push(field);
        if (row.some(f => f !== '') || rows.length === 0) {
            rows.push(row);
        }

        return rows;
    }

    // ── Show status ───────────────────────────────────────────
    function showStatus(msg, type = 'info') {
        statusEl.textContent = msg;
        statusEl.className = type;
        statusEl.style.display = 'block';
    }

    function hideStatus() {
        statusEl.style.display = 'none';
    }

    // ── Escape HTML ───────────────────────────────────────────
    function escapeHtml(str) {
        return str
            .replace(/&/g, '&amp;')
            .replace(/</g, '&lt;')
            .replace(/>/g, '&gt;')
            .replace(/"/g, '&quot;');
    }

    // ── Build table ───────────────────────────────────────────
    function buildTable(rows, hasHeader, trim, showRowNums) {
        if (rows.length === 0) return;

        // Optionally trim each field
        const data = trim
            ? rows.map(r => r.map(f => f.trim()))
            : rows;

        // Determine max column count
        const maxCols = data.reduce((m, r) => Math.max(m, r.length), 0);

        let headerRow = null;
        let bodyRows  = data;

        if (hasHeader && data.length > 0) {
            headerRow = data[0];
            bodyRows  = data.slice(1);
        }

        outputTable.innerHTML = '';

        // ── THEAD ──
        const thead = outputTable.createTHead();
        const htr = thead.insertRow();

        if (showRowNums) {
            const th = document.createElement('th');
            th.className = 'row-num';
            th.textContent = '#';
            htr.appendChild(th);
        }

        for (let c = 0; c < maxCols; c++) {
            const th = document.createElement('th');
            if (headerRow) {
                th.innerHTML = escapeHtml(headerRow[c] || '');
                const idx = document.createElement('span');
                idx.className = 'col-index';
                idx.textContent = `col ${c + 1}`;
                th.appendChild(idx);
            } else {
                th.innerHTML = `Column ${c + 1}<span class="col-index">col ${c + 1}</span>`;
            }
            htr.appendChild(th);
        }

        // ── TBODY ──
        const tbody = outputTable.createTBody();

        bodyRows.forEach((row, ri) => {
            const tr = tbody.insertRow();
            const isMismatched = row.length !== maxCols;

            if (showRowNums) {
                const td = tr.insertCell();
                td.className = 'row-num';
                td.textContent = ri + 1;
            }

            for (let c = 0; c < maxCols; c++) {
                const td = tr.insertCell();
                const val = row[c];

                if (val === undefined || val === '') {
                    td.textContent = val === undefined ? '' : '';
                    td.classList.add('empty-cell');
                    if (val === undefined) td.textContent = '—';
                    if (isMismatched && val === undefined) td.classList.add('mismatched');
                } else {
                    td.textContent = val;
                }
            }
        });

        // ── Meta info ──
        const totalRows = bodyRows.length;
        const warnings  = bodyRows.filter(r => r.length !== maxCols).length;
        let meta = `${totalRows} row${totalRows !== 1 ? 's' : ''} × ${maxCols} column${maxCols !== 1 ? 's' : ''}`;
        if (warnings > 0) meta += ` · ⚠️ ${warnings} row${warnings > 1 ? 's' : ''} with mismatched column count`;
        outputMeta.textContent = meta;
    }

    // ── Parse button ──────────────────────────────────────────
    parseBtn.addEventListener('click', () => {
        const raw = csvInput.value;

        if (!raw.trim()) {
            showStatus('⚠️ Please paste some CSV data first.', 'error');
            outputCard.style.display = 'none';
            return;
        }

        const delimiter = getDelimiter();

        let rows;
        try {
            rows = parseCSV(raw, delimiter);
        } catch (e) {
            showStatus(`❌ Parse error: ${e.message}`, 'error');
            return;
        }

        // Filter completely empty trailing rows
        while (rows.length > 0 && rows[rows.length - 1].every(f => f.trim() === '')) {
            rows.pop();
        }

        if (rows.length === 0) {
            showStatus('⚠️ No data found after parsing.', 'error');
            outputCard.style.display = 'none';
            return;
        }

        buildTable(rows, hasHeaderCb.checked, trimWsCb.checked, showRowNumsCb.checked);

        outputCard.style.display = 'block';
        outputCard.scrollIntoView({ behavior: 'smooth', block: 'start' });

        const rowCount = hasHeaderCb.checked ? rows.length - 1 : rows.length;
        showStatus(`✅ Parsed successfully — ${rowCount} data row${rowCount !== 1 ? 's' : ''} found.`, 'success');
    });

    // ── Sample button ─────────────────────────────────────────
    sampleBtn.addEventListener('click', () => {
        csvInput.value = SAMPLE_CSV;
        hideStatus();
        outputCard.style.display = 'none';
        csvInput.focus();
    });

    // ── Clear button ──────────────────────────────────────────
    clearBtn.addEventListener('click', () => {
        csvInput.value = '';
        outputCard.style.display = 'none';
        hideStatus();
        csvInput.focus();
    });

    // ── Copy HTML button ──────────────────────────────────────
    copyBtn.addEventListener('click', () => {
        const html = outputTable.outerHTML;
        navigator.clipboard.writeText(html).then(() => {
            const orig = copyBtn.textContent;
            copyBtn.textContent = '✅ Copied!';
            setTimeout(() => copyBtn.textContent = orig, 2000);
        }).catch(() => {
            showStatus('❌ Could not copy to clipboard.', 'error');
        });
    });

    // ── Allow Tab key in textarea ─────────────────────────────
    csvInput.addEventListener('keydown', e => {
        if (e.key === 'Tab') {
            e.preventDefault();
            const s = csvInput.selectionStart;
            const v = csvInput.value;
            csvInput.value = v.substring(0, s) + '\t' + v.substring(csvInput.selectionEnd);
            csvInput.selectionStart = csvInput.selectionEnd = s + 1;
        }
    });

    // ── Ctrl+Enter shortcut ───────────────────────────────────
    csvInput.addEventListener('keydown', e => {
        if ((e.ctrlKey || e.metaKey) && e.key === 'Enter') {
            parseBtn.click();
        }
    });
</script>
</body>
</html>
```

## What's included

**Parser features:**
- Full RFC 4180-compliant quoted field handling
- Commas (or any delimiter) inside `"quoted fields"` work correctly
- Escaped quotes via doubling (`""` → `"`)
- Quoted fields spanning multiple lines
- CRLF / LF / CR line endings all handled
- Varying column counts per row (mismatched cells highlighted in amber)

**UI features:**
- Delimiter selector — comma, semicolon, tab, pipe, or custom
- Toggle: first row as header, trim whitespace, row numbers
- Alternating row colors + hover highlight
- Row/column count summary with mismatch warnings
- **Load Sample** button with tricky edge cases pre-loaded
- **Copy HTML** button to grab the rendered table markup
- `Ctrl+Enter` keyboard shortcut to parse
- Responsive layout for mobile

