<script>
/* ═══════════════════════════════════════════════
   CSV PARSER
   Handles:
   - Quoted fields with commas inside
   - Escaped double-quotes ("")
   - Trailing newlines / CRLF
   - Custom delimiters
   - Rows with varying column counts
═══════════════════════════════════════════════ */
function parseCSV(text, delimiter) {
  const rows = [];
  let row = [];
  let field = '';
  let inQuotes = false;
  let i = 0;

  // Normalise line endings
  text = text.replace(/\r\n/g, '\n').replace(/\r/g, '\n');

  // Remove single trailing newline so we don't get a phantom empty row
  if (text.endsWith('\n')) text = text.slice(0, -1);

  const len = text.length;

  while (i < len) {
    const ch = text[i];

    if (inQuotes) {
      if (ch === '"') {
        // Peek ahead
        if (i + 1 < len && text[i + 1] === '"') {
          // Escaped quote ("")
          field += '"';
          i += 2;
        } else {
          // Closing quote
          inQuotes = false;
          i++;
        }
      } else {
        field += ch;
        i++;
      }
    } else {
      if (ch === '"') {
        inQuotes = true;
        i++;
      } else if (ch === delimiter) {
        row.push(field);
        field = '';
        i++;
      } else if (ch === '\n') {
        row.push(field);
        field = '';
        rows.push(row);
        row = [];
        i++;
      } else {
        field += ch;
        i++;
      }
    }
  }

  // Push last field and row
  row.push(field);
  if (row.length > 1 || row[0] !== '') {
    rows.push(row);
  }

  return rows;
}

/* ═══════════════════════════════════════════════
   AUTO-DETECT DELIMITER
   Counts candidate delimiters on first non-empty line
═══════════════════════════════════════════════ */
function detectDelimiter(text) {
  const candidates = [',', ';', '\t', '|'];
  const firstLine = text.split(/\r?\n/).find(l => l.trim() !== '') || '';

  let best = ',';
  let bestCount = 0;

  for (const d of candidates) {
    // Simple count (ignores quoted context – good enough for detection)
    const count = firstLine.split(d).length - 1;
    if (count > bestCount) {
      bestCount = count;
      best = d;
    }
  }

  return best;
}

/* ═══════════════════════════════════════════════
   RENDER TABLE
═══════════════════════════════════════════════ */
function renderTable(rows, firstRowIsHeader) {
  const table = document.getElementById('resultTable');
  table.innerHTML = '';

  if (rows.length === 0) return;

  // Find the maximum column count across all rows
  const maxCols = rows.reduce((m, r) => Math.max(m, r.length), 0);

  let headerRow = null;
  let dataRows = rows;

  if (firstRowIsHeader && rows.length > 0) {
    headerRow = rows[0];
    dataRows = rows.slice(1);
  }

  // ── THEAD ──
  if (headerRow) {
    const thead = document.createElement('thead');
    const tr = document.createElement('tr');

    for (let c = 0; c < maxCols; c++) {
      const th = document.createElement('th');
      const val = headerRow[c];
      if (val === undefined || val === '') {
        th.innerHTML = `<span class="empty-cell">col ${c + 1}</span>`;
      } else {
        th.textContent = val;
      }
      // Mark extra columns if header row is shorter
      if (c >= headerRow.length) {
        th.innerHTML += `<span class="mismatch-badge">+</span>`;
      }
      tr.appendChild(th);
    }

    thead.appendChild(tr);
    table.appendChild(thead);
  }

  // ── TBODY ──
  const tbody = document.createElement('tbody');

  for (const rowData of dataRows) {
    const tr = document.createElement('tr');

    for (let c = 0; c < maxCols; c++) {
      const td = document.createElement('td');
      const val = rowData[c];

      if (val === undefined) {
        td.innerHTML = `<span class="empty-cell">—</span>`;
      } else if (val.trim() === '') {
        td.innerHTML = `<span class="empty-cell">&nbsp;</span>`;
      } else {
        td.textContent = val;
      }

      // Visual hint for rows that have more columns than the header
      if (headerRow && c >= headerRow.length) {
        td.style.background = '#fffbe6';
      }

      tr.appendChild(td);
    }

    tbody.appendChild(tr);
  }

  table.appendChild(tbody);
}

/* ═══════════════════════════════════════════════
   MAIN ACTION
═══════════════════════════════════════════════ */
function parseAndRender() {
  const raw = document.getElementById('csvInput').value;
  const delimSetting = document.getElementById('delimSelect').value;
  const firstRowIsHeader = document.getElementById('headerCheck').checked;

  hideStatus();

  if (!raw.trim()) {
    showStatus('Please paste some CSV data first.', 'error');
    return;
  }

  let delimiter = delimSetting === 'auto' ? detectDelimiter(raw) : delimSetting;
  // Handle literal \t from select value
  if (delimiter === '\\t') delimiter = '\t';

  let rows;
  try {
    rows = parseCSV(raw, delimiter);
  } catch (e) {
    showStatus(`Parse error: ${e.message}`, 'error');
    return;
  }

  if (rows.length === 0) {
    showStatus('No data found after parsing.', 'error');
    return;
  }

  renderTable(rows, firstRowIsHeader);

  // Meta info
  const dataRowCount = firstRowIsHeader ? rows.length - 1 : rows.length;
  const maxCols = rows.reduce((m, r) => Math.max(m, r.length), 0);
  const delimLabel = delimiter === '\t' ? 'Tab' : `"${delimiter}"`;

  document.getElementById('tableMeta').innerHTML =
    `<strong>${dataRowCount}</strong> data row${dataRowCount !== 1 ? 's' : ''} &nbsp;·&nbsp;
     <strong>${maxCols}</strong> column${maxCols !== 1 ? 's' : ''} &nbsp;·&nbsp;
     Delimiter: <strong>${delimLabel}</strong>`;

  document.getElementById('output').style.display = 'block';
  showStatus(
    `✓ Successfully parsed ${rows.length} row${rows.length !== 1 ? 's' : ''}.`,
    'success'
  );

  // Scroll to output
  setTimeout(() => {
    document.getElementById('output').scrollIntoView({ behavior: 'smooth', block: 'start' });
  }, 100);
}

/* ═══════════════════════════════════════════════
   HELPERS
═══════════════════════════════════════════════ */
function showStatus(msg, type) {
  const el = document.getElementById('status');
  el.textContent = msg;
  el.className = `status ${type}`;
  el.style.display = 'block';
}

function hideStatus() {
  const el = document.getElementById('status');
