function copyTableHTML() {
  const table = document.getElementById('resultTable');
  const html = table.outerHTML;

  if (navigator.clipboard) {
    navigator.clipboard.writeText(html).then(() => {
      showStatus('✓ Table HTML copied to clipboard!', 'success');
    }).catch(() => fallbackCopy(html));
  } else {
    fallbackCopy(html);
  }
}

function fallbackCopy(text) {
  const ta = document.createElement('textarea');
  ta.value = text;
  ta.style.position = 'fixed';
  ta.style.opacity = '0';
  document.body.appendChild(ta);
  ta.select();
  try {
    document.execCommand('copy');
    showStatus('✓ Table HTML copied to clipboard!', 'success');
  } catch {
    showStatus('Could not copy automatically. Please copy manually.', 'error');
  }
  document.body.removeChild(ta);
}

// Allow Ctrl+Enter in textarea to trigger parse
document.getElementById('csvInput').addEventListener('keydown', function (e) {
