    <div class="container">
        <header>
            <h1>CSV → Table Converter</h1>
            <p>Paste your CSV data below, then click Parse to render it as a styled table</p>
        </header>

        <div class="input-section">
            <label>CSV Input</label>
            <textarea id="csvInput" placeholder='Paste CSV data here...&#10;&#10;Example:&#10;Name, Age, "City, State", Notes&#10;"Alice ""The Great""", 30, "New York, NY", "Loves coding"&#10;Bob, 25, "Los Angeles, CA", ""&#10;Charlie, 35, "Chicago, IL"'></textarea>

            <div class="controls">
                <button class="btn btn-primary" onclick="parseCSV()">⚡ Parse CSV</button>
                <button class="btn btn-secondary" onclick="clearAll()">✕ Clear</button>
                <button class="btn btn-load" onclick="loadSample()">↓ Load Sample</button>
                <div class="delimiter-group">
                    <label>Delimiter:</label>
                    <select id="delimiter">
                        <option value=",">Comma (,)</option>
                        <option value=";">Semicolon (;)</option>
                        <option value="	">Tab (\t)</option>
                        <option value="|">Pipe (|)</option>
                    </select>
                </div>
            </div>

            <div class="error-box" id="errorBox"></div>
        </div>

        <div class="output-section" id="outputSection">
            <div class="output-header">
                <h2>📊 Parsed Table</h2>
                <div class="stats" id="statsBar"></div>
            </div>
            <div class="table-wrapper">
                <table id="outputTable">
                    <thead id="tableHead"></thead>
                    <tbody id="tableBody"></tbody>
                </table>
            </div>
            <div class="legend" id="legend"></div>
        </div>
    </div>

    <script>
        // ─── CSV Parser ───────────────────────────────────────────────────────────
        function parseCSVData(text, delimiter) {
            const rows = [];
            let row = [];
            let field = '';
            let inQuotes = false;
            let i = 0;

            // Normalize line endings
            text = text.replace(/\r\n/g, '\n').replace(/\r/g, '\n');

            while (i < text.length) {
                const ch = text[i];
                const next = text[i + 1];

                if (inQuotes) {
                    if (ch === '"') {
                        // Escaped quote: "" → "
                        if (next === '"') {
                            field += '"';
                            i += 2;
                            continue;
                        }
                        // Closing quote
                        inQuotes = false;
                        i++;
                        continue;
                    }
                    field += ch;
                    i++;
                } else {
                    if (ch === '"') {
                        inQuotes = true;
                        i++;
                        continue;
                    }

                    if (ch === delimiter || (delimiter === '\t' && ch === '\t')) {
                        row.push(field);
                        field = '';
                        i++;
                        continue;
                    }

                    if (ch === '\n') {
                        row.push(field);
                        field = '';
                        // Skip empty trailing newlines only at end
                        rows.push(row);
                        row = [];
                        i++;
                        continue;
                    }

                    field += ch;
                    i++;
                }
            }

            // Last field / row
            if (field !== '' || row.length > 0) {
                row.push(field);
                rows.push(row);
            }

            // Remove completely empty trailing rows
            while (rows.length > 0 && rows[rows.length - 1].every(c => c.trim() === '')) {
                rows.pop();
            }

            return rows;
        }

        // ─── Main Parse & Render ─────────────────────────────────────────────────
        function parseCSV() {
            const raw = document.getElementById('csvInput').value;
            const delimiterSelect = document.getElementById('delimiter');
            const delimiter = delimiterSelect.value;

            const errorBox = document.getElementById('errorBox');
            errorBox.classList.remove('visible');

            if (!raw.trim()) {
                showError('Please paste some CSV data before parsing.');
                return;
            }

            let rows;
            try {
                rows = parseCSVData(raw, delimiter);
            } catch (e) {
                showError('Parsing error: ' + e.message);
                return;
            }

            if (rows.length === 0) {
                showError('No data found after parsing. Please check your input.');
                return;
            }

            // Determine max column count
            const maxCols = Math.max(...rows.map(r => r.length));

            const headerRow = rows[0];
            const dataRows = rows.slice(1);

            // Build header
            const thead = document.getElementById('tableHead');
            thead.innerHTML = '';
            const tr = document.createElement('tr');
            for (let c = 0; c < maxCols; c++) {
                const th = document.createElement('th');
                const indexSpan = document.createElement('span');
                indexSpan.className = 'col-index';
                indexSpan.textContent = c + 1;
                th.appendChild(indexSpan);

                const label = (headerRow[c] !== undefined && headerRow[c].trim() !== '')
                    ? headerRow[c]
                    : `Column ${c + 1}`;
                th.appendChild(document.createTextNode(label));
                tr.appendChild(th);
            }
            thead.appendChild(tr);

            // Build body
            const tbody = document.getElementById('tableBody');
            tbody.innerHTML = '';

            let hasExtra = false;
            let hasMissing = false;

            dataRows.forEach((rowData, rowIdx) => {
                const tr = document.createElement('tr');
                for (let c = 0; c < maxCols; c++) {
                    const td = document.createElement('td');

                    if (c >= rowData.length) {
                        // Missing cell
                        td.textContent = '—';
                        td.classList.add('missing-cell');
                        hasMissing = true;
                    } else {
                        const value = rowData[c];
                        if (value === '') {
                            td.textContent = '(empty)';
                            td.classList.add('empty-cell');
                        } else {
                            td.textContent = value;
                        }

                        // Extra cell (beyond header column count)
                        if (c >= headerRow.length) {
                            td.classList.add('extra-cell');
                            hasExtra = true;
                        }
                    }

                    tr.appendChild(td);
                }
                tbody.appendChild(tr);
            });

            // Stats
            const statsBar = document.getElementById('statsBar');
            statsBar.innerHTML = `
                <span class="stat-badge">Rows: ${dataRows.length}</span>
                <span class="stat-badge">Columns: ${maxCols}</span>
                <span class="stat-badge">Total Cells: ${dataRows.length * maxCols}</span>
            `;

            // Legend
            const legend = document.getElementById('legend');
            legend.innerHTML = '';
            const legendItems = [];
            if (hasExtra) {
                legendItems.push({ cls: 'extra', label: 'Extra column (beyond header)' });
            }
            if (hasMissing) {
                legendItems.push({ cls: 'missing', label: 'Missing value (row has fewer columns)' });
            }
            legendItems.push({ cls: 'empty', label: 'Empty string field' });

            legendItems.forEach(item => {
                const div = document.createElement('div');
                div.className = 'legend-item';
                div.innerHTML = `<span class="legend-dot ${item.cls}"></span>${item.label}`;
                legend.appendChild(div);
            });

            // Show output
            const outputSection = document.getElementById('outputSection');
            outputSection.classList.add('visible');
            outputSection.scrollIntoView({ behavior: 'smooth', block: 'start' });
        }

        // ─── Helpers ─────────────────────────────────────────────────────────────
        function showError(msg) {
            const errorBox = document.getElementById('errorBox');
            errorBox.textContent = '⚠ ' + msg;
            errorBox.classList.add('visible');
            document.getElementById('outputSection').classList.remove('visible');
        }

        function clearAll() {
            document.getElementById('csvInput').value = '';
            document.getElementById('outputSection').classList.remove('visible');
            document.getElementById('errorBox').classList.remove('visible');
        }

        function loadSample() {
            const sample = `Name,Age,"City, State",Occupation,Notes
"Alice ""The Great""",30,"New York, NY",Engineer,"Loves coding, coffee"
Bob,25,"Los Angeles, CA",Designer,""
Charlie,35,"Chicago, IL",Manager,"Works remotely"
"Diana, PhD",28,"Austin, TX",Researcher,"Published ""3 papers"""
Eve,22,"Seattle, WA",Student
Frank,40,"Boston, MA",Director,"Joined in ""2010""","Extra column data"`;
            document.getElementById('csvInput').value = sample;
            document.getElementById('errorBox').classList.remove('visible');
        }

        // Allow Tab key in textarea
        document.getElementById('csvInput').addEventListener('keydown', function (e) {
            if (e.key === 'Tab') {
                e.preventDefault();
                const start = this.selectionStart;
                const end = this.selectionEnd;
                this.value = this.value.substring(0, start) + '\t' + this.value.substring(end);
                this.selectionStart = this.selectionEnd = start + 1;
            }
        });

        // Parse on Ctrl+Enter
        document.getElementById('csvInput').addEventListener('keydown', function (e) {
            if ((e.ctrlKey || e.metaKey) && e.key === 'Enter') {
                parseCSV();
            }
        });
    </script>
</body>
</html>
