  <script>
    // ── CSV Parser ──────────────────────────────────────────────────────────────
    // Handles: quoted fields, commas inside quotes, escaped double-quotes (""),
    // newlines inside quoted fields, and varying column counts.
    function parseCSVData(text, delimiter) {
      const rows = [];
      let col = 0;
      let row = [];
      let i = 0;
      const n = text.length;

      while (i < n) {
        const ch = text[i];

        if (ch === '"') {
          // Quoted field
          let field = '';
          i++; // skip opening quote
          while (i < n) {
            if (text[i] === '"') {
              if (i + 1 < n && text[i + 1] === '"') {
                // Escaped quote
                field += '"';
                i += 2;
              } else {
                // Closing quote
                i++;
                break;
              }
            } else {
              field += text[i];
              i++;
            }
          }
          row.push(field);
          // After closing quote, skip optional whitespace then expect delimiter or newline
          while (i < n && text[i] === ' ') i++;
          if (i < n && text[i] === delimiter) i++;
          else if (i < n && text[i] === '\r') {
            i++;
            if (i < n && text[i] === '\n') i++;
            rows.push(row);
            row = [];
          } else if (i < n && text[i] === '\n') {
            i++;
            rows.push(row);
            row = [];
          }
        } else if (ch === '\r' || ch === '\n') {
          // End of row
          row.push('');
          // Actually pop the last empty push — we already pushed in delimiter branch
          // Let's handle more carefully: unquoted empty field at end of line
          // We handle row termination here
          if (ch === '\r' && i + 1 < n && text[i + 1] === '\n') i++;
          i++;
          rows.push(row);
          row = [];
        } else {
          // Unquoted field
          let field = '';
          while (i < n && text[i] !== delimiter && text[i] !== '\r' && text[i] !== '\n') {
            field += text[i];
            i++;
          }
          row.push(field.trimEnd());
          if (i < n && text[i] === delimiter) {
            i++;
          } else if (i < n && (text[i] === '\r' || text[i] === '\n')) {
            if (text[i] === '\r' && i + 1 < n && text[i + 1] === '\n') i++;
            i++;
            rows.push(row);
            row = [];
          }
        }
      }

      // Push last row if it has content
      if (row.length > 0) {
        rows.push(row);
      }

      return rows;
    }

    // ── Re-parse with proper RFC 4180 logic ────────────────────────────────────
    function robustParse(text, delimiter) {
      // Normalize line endings
      text = text.replace(/\r\n/g, '\n').replace(/\r/g, '\n');

      const rows = [];
      let i = 0;
      const len = text.length;

      while (i <= len) {
        const row = [];

        // Parse one row
        while (true) {
          if (i >= len || text[i] === '\n') {
            // End of text or line without reading a field yet means empty last row
            // We handle empty trailing newline below
            break;
          }

          // Parse one field
          if (text[i] === '"') {
            // Quoted field
            i++; // consume opening quote
            let field = '';
            while (i < len) {
              if (text[i] === '"') {
                if (i + 1 < len && text[i + 1] === '"') {
                  field += '"';
                  i += 2;
                } else {
                  i++; // consume closing quote
                  break;
                }
              } else {
                field += text[i++];
              }
            }
            row.push(field);
            // skip whitespace after closing quote (lenient)
            while (i < len && text[i] === ' ') i++;
          } else {
            // Unquoted field
            let field = '';
            while (i < len && text[i] !== delimiter && text[i] !== '\n') {
              field += text[i++];
            }
            row.push(field.trim());
          }

          // After field: delimiter or end of line
          if (i < len && text[i] === delimiter) {
            i++; // consume delimiter, continue to next field
          } else {
            break; // end of row
          }
        }

        if (i < len && text[i] === '\n') i++; // consume newline

        if (row.length > 0) {
          rows.push(row);
        }

        if (i >= len) break;
      }

      return rows;
    }

    // ── Build HTML Table ────────────────────────────────────────────────────────
    function buildTable(rows) {
      if (!rows || rows.length === 0) return null;

      // Find max columns
      const maxCols = Math.max(...rows.map(r => r.length));

      const table = document.createElement('table');

      // Header row (first row)
      const thead = document.createElement('thead');
      const headerRow = document.createElement('tr');

      // Row number header cell
      const thNum = document.createElement('th');
      thNum.textContent = '#';
      thNum.style.textAlign = 'center';
      headerRow.appendChild(thNum);

      const headerData = rows[0];
      for (let c = 0; c < maxCols; c++) {
        const th = document.createElement('th');
        const val = headerData[c] !== undefined ? headerData[c] : '';
        th.innerHTML = val !== ''
          ? `${escapeHTML(val)}<span class="col-index">Col ${c + 1}</span>`
          : `<span style="opacity:0.5">Column ${c + 1}</span><span class="col-index">Col ${c + 1}</span>`;
        headerRow.appendChild(th);
      }
      thead.appendChild(headerRow);
      table.appendChild(thead);

      // Body rows
      const tbody = document.createElement('tbody');
      for (let r = 1; r < rows.length; r++) {
        const tr = document.createElement('tr');

        // Row number
        const tdNum = document.createElement('td');
        tdNum.className = 'row-num';
        tdNum.textContent = r;
        tr.appendChild(tdNum);

        for (let c = 0; c < maxCols; c++) {
          const td = document.createElement('td');
          if (rows[r][c] === undefined) {
            td.textContent = '—';
            td.className = 'missing-cell';
          } else if (rows[r][c] === '') {
            td.textContent = '(empty)';
            td.className = 'empty-cell';
          } else {
            td.textContent = rows[r][c];
          }
          tr.appendChild(td);
        }
        tbody.appendChild(tr);
      }
      table.appendChild(tbody);

      return table;
    }

    function escapeHTML(str) {
      return str
        .replace(/&/g, '&amp;')
        .replace(/</g, '&lt;')
        .replace(/>/g, '&gt;')
        .replace(/"/g, '&quot;');
    }

    // ── Status Bar ──────────────────────────────────────────────────────────────
    function showStatus(type, message) {
      const bar = document.getElementById('statusBar');
      bar.className = `status-bar ${type}`;
      const icons = { success: '✅', error: '❌', info: 'ℹ️' };
      bar.innerHTML = `<span>${icons[type] || ''}</span> ${message}`;
    }

    function hideStatus() {
      document.getElementById('statusBar').className = 'status-bar hidden';
    }

    // ── Main Parse Action ───────────────────────────────────────────────────────
    function parseCSV() {
      const raw = document.getElementById('csvInput').value;
      const delimiter = document.getElementById('delimSelect').value;

      if (!raw.trim()) {
        showStatus('error', 'Please paste some CSV data first.');
        document.getElementById('outputCard').classList.remove('visible');
        return;
      }

      let rows;
      try {
        rows = robustParse(raw, delimiter);
      } catch (e) {
        showStatus('error', 'Parsing failed: ' + e.message);
        return;
      }

      // Filter out completely empty rows
      const filteredRows = rows.filter(r => r.some(cell => cell !== ''));

      if (filteredRows.length === 0) {
        showStatus('error', 'No data found after parsing. Check your delimiter selection.');
        document.getElementById('outputCard').classList.remove('visible');
        return;
      }

      const maxCols = Math.max(...filteredRows.map(r => r.length));
      const dataRows = filteredRows.length - 1;

      // Check for varying column counts
      const colCounts = filteredRows.map(r => r.length);
      const hasVaryingCols = new Set(colCounts).size > 1;

      // Build table
      const table = buildTable(filteredRows);
      const wrapper = document.getElementById('tableWrapper');
      wrapper.innerHTML = '';
      wrapper.appendChild(table);

      // Stats
      const statsEl = document.getElementById('tableStats');
      statsEl.innerHTML = `
        <span class="stat-badge">📏 ${dataRows} data row${dataRows !== 1 ? 's' : ''}</span>
        <span class="stat-badge">📐 ${maxCols} column${maxCols !== 1 ? 's' : ''}</span>
        <span class="stat-badge">🔢 ${filteredRows.length} total rows (incl. header)</span>
        ${hasVaryingCols ? '<span class="stat-badge" style="background:#fff3cd;border-color:#ffc107;color:#856404;">⚠️ Varying column counts detected</span>' : ''}
      `;

      // Show output card
      document.getElementById('outputCard').classList.add('visible');

      showStatus('success', `Successfully parsed ${filteredRows.length} rows × ${maxCols} columns.`);

      // Scroll to output
      setTimeout(() => {
        document.getElementById('outputCard').scrollIntoView({ behavior: 'smooth', block: 'start' });
      }, 100);
    }

    // ── Load Sample ─────────────────────────────────────────────────────────────
    function loadSample() {
      document.getElementById('csvInput').value =
`Name,Age,City,Occupation,Notes
