Bob,,Tokyo,Artist,"Enjoys painting
and sculpture"
"O'Brien, Mike",35,"Los Angeles",Developer,Senior
Charlie,22,Berlin,Student,"Studying CS, Math, and Physics"`;
      document.getElementById('delimSelect').value = ',';
      hideStatus();
      document.getElementById('outputCard').classList.remove('visible');
    }

    // ── Clear All ───────────────────────────────────────────────────────────────
    function clearAll() {
      document.getElementById('csvInput').value = '';
      document.getElementById('tableWrapper').innerHTML = '';
      document.getElementById('tableStats').innerHTML = '';
      document.getElementById('outputCard').classList.remove('visible');
      hideStatus();
    }

    // ── Keyboard shortcut: Ctrl+Enter to parse ──────────────────────────────────
    document.getElementById('csvInput').addEventListener('keydown', function(e) {
      if ((e.ctrlKey || e.metaKey) && e.key === 'Enter') {
        e.preventDefault();
        parseCSV();
      }
    });
  </script>
</body>
