<script>
  // ─── Core parser ────────────────────────────────────────────────────────────
  // Implements RFC 4180 properly:
  //   • Fields may be enclosed in double-quotes.
  //   • A double-quote inside a quoted field is escaped as two double-quotes ("").
  //   • Commas inside quoted fields are treated as literal characters.
  //   • Newlines inside quoted fields are preserved.
  function parseCSV(text) {
    const rows = [];
    let row = [];
    let i = 0;
    const len = text.length;

    while (i < len) {
      // ── quoted field ──────────────────────────────────────────────────────
      if (text[i] === '"') {
        i++; // skip opening quote
        let field = '';

        while (i < len) {
          if (text[i] === '"') {
            // peek ahead: two double-quotes → escaped quote
            if (i + 1 < len && text[i + 1] === '"') {
              field += '"';
              i += 2;
            } else {
              // closing quote
              i++;
              break;
            }
          } else {
            field += text[i];
            i++;
          }
        }

        row.push(field);

        // after closing quote, expect comma, CR, LF, or end-of-string
        if (i < len) {
          if (text[i] === ',') {
            i++; // consume comma, next iteration reads next field
          } else if (text[i] === '\r') {
            i++;
            if (i < len && text[i] === '\n') i++;
            rows.push(row);
            row = [];
          } else if (text[i] === '\n') {
            i++;
            rows.push(row);
            row = [];
          }
          // anything else (malformed) — just continue
        }

      // ── unquoted field ────────────────────────────────────────────────────
      } else {
        let field = '';

        while (i < len && text[i] !== ',' && text[i] !== '\n' && text[i] !== '\r') {
          field += text[i];
          i++;
        }

        row.push(field);

        if (i < len) {
          if (text[i] === ',') {
            i++;
          } else if (text[i] === '\r') {
            i++;
            if (i < len && text[i] === '\n') i++;
            rows.push(row);
            row = [];
          } else if (text[i] === '\n') {
            i++;
            rows.push(row);
            row = [];
          }
        }
      }
    }

    // push last row if it has content
    if (row.length > 0) {
      rows.push(row);
    }

    return rows;
  }

  // ─── Render ──────────────────────────────────────────────────────────────────
  function render(rows) {
    const output = document.getElementById('output');

    if (!rows || rows.length === 0) {
      output.innerHTML = '<div class="error">No data found. Please check your input.</div>';
      return;
    }

    // filter out completely empty trailing rows
    while (rows.length > 0 && rows[rows.length - 1].every(c => c === '')) {
      rows.pop();
    }

    if (rows.length === 0) {
      output.innerHTML = '<div class="error">No data found. Please check your input.</div>';
      return;
    }

    const headers = rows[0];
    const dataRows = rows.slice(1);

    // normalise: pad shorter rows to header length
    const colCount = headers.length;
    dataRows.forEach(r => {
      while (r.length < colCount) r.push('');
    });

    let html = `<div class="stats">
      Parsed <span>${dataRows.length}</span> row${dataRows.length !== 1 ? 's' : ''}
      across <span>${colCount}</span> column${colCount !== 1 ? 's' : ''}
    </div>
    <div class="table-wrapper"><table>
      <thead><tr>
        <th class="row-num">#</th>`;

    headers.forEach(h => {
      html += `<th>${escHtml(h)}</th>`;
    });

    html += `</tr></thead><tbody>`;

    dataRows.forEach((row, idx) => {
      html += `<tr><td class="row-num">${idx + 1}</td>`;
      for (let c = 0; c < colCount; c++) {
        const val = row[c] !== undefined ? row[c] : '';
        html += val === ''
          ? `<td><span class="empty-cell">empty</span></td>`
          : `<td>${escHtml(val)}</td>`;
      }
      html += `</tr>`;
    });

    html += `</tbody></table></div>`;
    output.innerHTML = html;
  }

  function escHtml(str) {
    return str
      .replace(/&/g, '&amp;')
      .replace(/</g, '&lt;')
      .replace(/>/g, '&gt;')
      .replace(/"/g, '&quot;')
      .replace(/\n/g, '<br>');
  }

  // ─── Sample data ─────────────────────────────────────────────────────────────
  const SAMPLE = `name,age,city,notes
