<body>
  <div class="container">
    <h1>CSV Parser</h1>

    <textarea id="csvInput" placeholder='Paste CSV here, e.g.:
name,age,city
"Smith, John",30,"New York"
"Jane ""JJ"" Doe",25,Boston
Alice,22,"Austin, TX"'></textarea>

    <button onclick="parseAndRender()">Parse CSV</button>

    <div id="error" class="error hidden"></div>
    <div id="info" class="info hidden"></div>

    <div class="table-wrapper hidden" id="tableWrapper">
      <table id="outputTable">
        <thead id="tableHead"></thead>
        <tbody id="tableBody"></tbody>
      </table>
    </div>
  </div>

  <script>
    /**
     * Parses a CSV string into a 2D array.
     * Handles:
     *  - Commas inside double-quoted fields
     *  - Escaped quotes ("") inside quoted fields
     *  - Newlines inside quoted fields
     *  - Leading/trailing whitespace outside quotes
     */
    function parseCSV(text) {
      const rows = [];
      let row = [];
      let i = 0;
      const len = text.length;

      while (i < len) {
        // Skip carriage returns cleanly
        if (text[i] === '\r') {
          i++;
          continue;
        }

        // Newline outside a field = end of row
        if (text[i] === '\n') {
          rows.push(row);
          row = [];
          i++;
          continue;
        }

        // Quoted field
        if (text[i] === '"') {
          let field = '';
          i++; // skip opening quote

          while (i < len) {
            if (text[i] === '"') {
              // Escaped quote ("")
              if (i + 1 < len && text[i + 1] === '"') {
                field += '"';
                i += 2;
              } else {
                // Closing quote
                i++;
                break;
              }
            } else {
              field += text[i];
              i++;
            }
          }

          row.push(field);

          // Skip whitespace after closing quote before comma or newline
          while (i < len && text[i] === ' ') i++;

          // Expect comma or end of line
          if (i < len && text[i] === ',') i++;

        } else {
          // Unquoted field — read until comma or newline
          let field = '';
          while (i < len && text[i] !== ',' && text[i] !== '\n' && text[i] !== '\r') {
            field += text[i];
            i++;
          }

          row.push(field.trim());

          if (i < len && text[i] === ',') i++;
        }
      }

      // Push last row if it has content
      if (row.length > 0) {
        rows.push(row);
      }

      return rows;
    }

    function parseAndRender() {
      const input = document.getElementById('csvInput').value;
      const errorEl = document.getElementById('error');
      const tableWrapper = document.getElementById('tableWrapper');
      const infoEl = document.getElementById('info');

      // Reset
      errorEl.classList.add('hidden');
      tableWrapper.classList.add('hidden');
      infoEl.classList.add('hidden');

      if (!input.trim()) {
        showError('Please paste some CSV data first.');
        return;
      }

      let rows;
      try {
        rows = parseCSV(input);
      } catch (e) {
        showError('Parse error: ' + e.message);
        return;
      }

      // Filter out completely empty rows
      const filtered = rows.filter(r => r.some(cell => cell !== ''));

      if (filtered.length === 0) {
        showError('No data found in input.');
        return;
      }

      const headers = filtered[0];
      const dataRows = filtered.slice(1);

      // Build header
      const thead = document.getElementById('tableHead');
      const tbody = document.getElementById('tableBody');
      thead.innerHTML = '';
      tbody.innerHTML = '';

      const headerRow = document.createElement('tr');
      headers.forEach(h => {
        const th = document.createElement('th');
        th.textContent = h;
        headerRow.appendChild(th);
      });
      thead.appendChild(headerRow);

      // Build body
      dataRows.forEach(rowData => {
        const tr = document.createElement('tr');
        // Pad row if fewer columns than header
        for (let c = 0; c < headers.length; c++) {
          const td = document.createElement('td');
          td.textContent = rowData[c] !== undefined ? rowData[c] : '';
          tr.appendChild(td);
        }
        tbody.appendChild(tr);
      });

      tableWrapper.classList.remove('hidden');
      infoEl.textContent = `${dataRows.length} row${dataRows.length !== 1 ? 's' : ''} × ${headers.length} column${headers.length !== 1 ? 's' : ''}`;
      infoEl.classList.remove('hidden');
    }

    function showError(msg) {
      const el = document.getElementById('error');
      el.textContent = msg;
      el.classList.remove('hidden');
    }
  </script>
</body>
</html>
